import{_ as n,c as a,o as s,d as e}from"./app.6040d904.js";const f='{"title":"Autenticaci\xF3n - API de Laravel","description":"","frontmatter":{},"headers":[{"level":2,"title":"Configuraci\xF3n de CORS","slug":"configuracion-de-cors"},{"level":2,"title":"Configuraci\xF3n de Fortify","slug":"configuracion-de-fortify"},{"level":2,"title":"Redirigir si est\xE1 Autenticado","slug":"redirigir-si-esta-autenticado"},{"level":2,"title":"Verificaci\xF3n de Email","slug":"verificacion-de-email"},{"level":2,"title":"Restablecer la Contrase\xF1a","slug":"restablecer-la-contrasena"},{"level":2,"title":"Rutas API","slug":"rutas-api"}],"relativePath":"laravel/laravel-authentication.md"}',t={},o=e(`<h1 id="autenticacion-api-de-laravel" tabindex="-1">Autenticaci\xF3n - API de Laravel <a class="header-anchor" href="#autenticacion-api-de-laravel" aria-hidden="true">#</a></h1><h2 id="configuracion-de-cors" tabindex="-1">Configuraci\xF3n de CORS <a class="header-anchor" href="#configuracion-de-cors" aria-hidden="true">#</a></h2><p>Si no configura CORS correctamente, puede ser la causa (perd\xF3n por el juego de palabras) de una gran frustraci\xF3n. Lo primero que debe recordar es que su SPA y API deben ejecutarse en el mismo dominio de nivel superior. Sin embargo, pueden colocarse en diferentes subdominios. Al ejecutarse localmente, con <code>php artisan serve</code> la API se ejecutar\xE1 en <code>http://localhost:8000</code>. Y el SPA, que usa Vite, normalmente se ejecutar\xE1 con <code>npm run dev</code> en <code>http://localhost:3000</code> (el puerto puede variar, pero est\xE1 bien).</p><p>Con esto en su lugar, solo necesitamos agregar las rutas que se permitir\xE1n a trav\xE9s de CORS. La mayor\xEDa de los puntos finales de la API se realizar\xE1n a trav\xE9s de <code>api/*</code>, pero Fortify tiene varios puntos finales que debe agregar junto con la obtenci\xF3n de <code>&#39;sanctum/csrf-cookie&#39;</code>, agregue lo siguiente en su archivo <code>config/cors.php</code>:</p><div class="language-php"><pre><code><span class="token string single-quoted-string">&#39;paths&#39;</span> <span class="token operator">=&gt;</span> <span class="token punctuation">[</span>
  <span class="token string single-quoted-string">&#39;api/*&#39;</span><span class="token punctuation">,</span>
  <span class="token string single-quoted-string">&#39;login&#39;</span><span class="token punctuation">,</span>
  <span class="token string single-quoted-string">&#39;logout&#39;</span><span class="token punctuation">,</span>
  <span class="token string single-quoted-string">&#39;register&#39;</span><span class="token punctuation">,</span>
  <span class="token string single-quoted-string">&#39;user/password&#39;</span><span class="token punctuation">,</span>
  <span class="token string single-quoted-string">&#39;forgot-password&#39;</span><span class="token punctuation">,</span>
  <span class="token string single-quoted-string">&#39;reset-password&#39;</span><span class="token punctuation">,</span>
  <span class="token string single-quoted-string">&#39;sanctum/csrf-cookie&#39;</span><span class="token punctuation">,</span>
  <span class="token string single-quoted-string">&#39;user/profile-information&#39;</span><span class="token punctuation">,</span>
  <span class="token string single-quoted-string">&#39;email/verification-notification&#39;</span><span class="token punctuation">,</span>
<span class="token punctuation">]</span><span class="token punctuation">,</span>
</code></pre></div><p>Mientras est\xE9 en el archivo <code>config/cors.php</code>, configure lo siguiente:</p><div class="language-php"><pre><code><span class="token string single-quoted-string">&#39;supports_credentials&#39;</span> <span class="token operator">=&gt;</span> <span class="token constant boolean">true</span><span class="token punctuation">,</span>
</code></pre></div><p>Lo anterior asegura que tiene el encabezado <code>Access-Control-Allow-Credentials</code> con un valor de <code>true</code> establecido. Puedes leer m\xE1s sobre esto en la <a href="https://developer.mozilla.org/en-US/docs/Web/HTTP/Headers/Access-Control-Allow-Credentials" target="_blank" rel="noopener noreferrer">documentaci\xF3n de MDN</a>. Pasaremos este encabezado a trav\xE9s del SPA, pero hablaremos m\xE1s de eso cuando pasemos a <a href="./../vue/axios-wrapper.html#objeto-init">configurarlo</a>.</p><h2 id="configuracion-de-fortify" tabindex="-1">Configuraci\xF3n de Fortify <a class="header-anchor" href="#configuracion-de-fortify" aria-hidden="true">#</a></h2><p>Fortify tambi\xE9n tiene un archivo de configuraci\xF3n (<code>config/fortify.php</code>) que necesitar\xE1 algunos cambios. Primero configure la variable <code>home</code> para que apunte a la URL de SPA, esto se puede hacer a trav\xE9s de la variable <code>.env</code>. Aqu\xED es donde la API se redirige durante la autenticaci\xF3n o el restablecimiento de contrase\xF1a cuando las operaciones son exitosas y el usuario est\xE1 autenticado.</p><div class="language-php"><pre><code><span class="token string single-quoted-string">&#39;home&#39;</span> <span class="token operator">=&gt;</span> <span class="token function">env</span><span class="token punctuation">(</span><span class="token string single-quoted-string">&#39;SPA_URL&#39;</span><span class="token punctuation">)</span> <span class="token operator">.</span> <span class="token string single-quoted-string">&#39;/dashboard&#39;</span><span class="token punctuation">,</span>
</code></pre></div><p>A continuaci\xF3n, apague el uso de cualquier vista de Laravel para las funciones de autenticaci\xF3n, el SPA se encarga de todo esto.</p><div class="language-php"><pre><code><span class="token string single-quoted-string">&#39;views&#39;</span> <span class="token operator">=&gt;</span> <span class="token constant boolean">false</span><span class="token punctuation">,</span>
</code></pre></div><p>Finalmente, active las funciones de autenticaci\xF3n que le gustar\xEDa usar:</p><div class="language-php"><pre><code><span class="token string single-quoted-string">&#39;features&#39;</span> <span class="token operator">=&gt;</span> <span class="token punctuation">[</span>
  <span class="token class-name static-context">Features</span><span class="token operator">::</span><span class="token function">registration</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">,</span>
  <span class="token class-name static-context">Features</span><span class="token operator">::</span><span class="token function">resetPasswords</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">,</span>
  <span class="token class-name static-context">Features</span><span class="token operator">::</span><span class="token function">emailVerification</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">,</span>
  <span class="token class-name static-context">Features</span><span class="token operator">::</span><span class="token function">updateProfileInformation</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">,</span>
  <span class="token class-name static-context">Features</span><span class="token operator">::</span><span class="token function">updatePasswords</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">,</span>
<span class="token punctuation">]</span><span class="token punctuation">,</span>
</code></pre></div><h2 id="redirigir-si-esta-autenticado" tabindex="-1">Redirigir si est\xE1 Autenticado <a class="header-anchor" href="#redirigir-si-esta-autenticado" aria-hidden="true">#</a></h2><p>Laravel proporciona un middleware <code>RedirectIfAuthenticated</code> que intentar\xE1 y lo redirigir\xE1 a la vista <code>home</code> si ya est\xE1 autenticado. Para que el SPA funcione, puede agregar lo siguiente, que simplemente enviar\xE1 un mensaje de \xE9xito 200 en una respuesta JSON. Luego manejaremos la redirecci\xF3n a la p\xE1gina de inicio del SPA utilizando el enrutamiento VueJS.</p><div class="language-php"><pre><code><span class="token keyword">foreach</span> <span class="token punctuation">(</span><span class="token variable">$guards</span> <span class="token keyword">as</span> <span class="token variable">$guard</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token class-name static-context">Auth</span><span class="token operator">::</span><span class="token function">guard</span><span class="token punctuation">(</span><span class="token variable">$guard</span><span class="token punctuation">)</span><span class="token operator">-&gt;</span><span class="token function">check</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
      <span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token variable">$request</span><span class="token operator">-&gt;</span><span class="token function">expectsJson</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
        <span class="token keyword">return</span> <span class="token function">response</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token operator">-&gt;</span><span class="token function">json</span><span class="token punctuation">(</span><span class="token punctuation">[</span><span class="token string single-quoted-string">&#39;error&#39;</span> <span class="token operator">=&gt;</span> <span class="token string single-quoted-string">&#39;Already authenticated.&#39;</span><span class="token punctuation">]</span><span class="token punctuation">,</span> <span class="token number">200</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
      <span class="token punctuation">}</span>
      <span class="token keyword">return</span> <span class="token function">redirect</span><span class="token punctuation">(</span><span class="token class-name static-context">RouteServiceProvider</span><span class="token operator">::</span><span class="token constant">HOME</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre></div><h2 id="verificacion-de-email" tabindex="-1">Verificaci\xF3n de Email <a class="header-anchor" href="#verificacion-de-email" aria-hidden="true">#</a></h2><p>Laravel puede manejar la verificaci\xF3n de correo electr\xF3nico como lo har\xEDa normalmente, pero con un peque\xF1o ajuste en el middleware de autenticaci\xF3n. Primero. Asegur\xE9monos de que su <code>App\\Models\\User</code> implemente el contrato <code>MustVerifyEmail</code>:</p><div class="language-php"><pre><code><span class="token keyword">class</span> <span class="token class-name-definition class-name">User</span> <span class="token keyword">extends</span> <span class="token class-name">Authenticatable</span> <span class="token keyword">implements</span> <span class="token class-name">MustVerifyEmail</span>
<span class="token punctuation">{</span>
    <span class="token keyword">use</span> <span class="token package">Notifiable</span><span class="token punctuation">;</span>

    <span class="token comment">//...</span>
<span class="token punctuation">}</span>
</code></pre></div><p>En el middleware <code>Authenticate</code>, cambie el m\xE9todo <code>redirectTo</code> para redirigir a la URL de SPA en lugar de a una vista de Laravel:</p><div class="language-php"><pre><code><span class="token keyword">protected</span> <span class="token keyword">function</span> <span class="token function-definition function">redirectTo</span><span class="token punctuation">(</span><span class="token variable">$request</span><span class="token punctuation">)</span>
<span class="token punctuation">{</span>
    <span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token operator">!</span> <span class="token variable">$request</span><span class="token operator">-&gt;</span><span class="token function">expectsJson</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
        <span class="token keyword">return</span> <span class="token function">url</span><span class="token punctuation">(</span><span class="token function">env</span><span class="token punctuation">(</span><span class="token string single-quoted-string">&#39;SPA_URL&#39;</span><span class="token punctuation">)</span> <span class="token operator">.</span> <span class="token string single-quoted-string">&#39;/login&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre></div><p>Con esto en su lugar, Laravel ahora enviar\xE1 el correo electr\xF3nico de verificaci\xF3n y cuando un usuario haga clic en el enlace de verificaci\xF3n, realizar\xE1 las comprobaciones de seguridad necesarias y lo redirigir\xE1 a la URL de su SPA.</p><h2 id="restablecer-la-contrasena" tabindex="-1">Restablecer la Contrase\xF1a <a class="header-anchor" href="#restablecer-la-contrasena" aria-hidden="true">#</a></h2><p>Configurar la funcionalidad de restablecimiento de contrase\xF1a en la API es tan simple como seguir los <a href="https://laravel.com/docs/8.x/passwords#reset-link-customization" target="_blank" rel="noopener noreferrer">documentos oficiales</a>. Como referencia, esto es lo que debe hacer.</p><p>Agregue lo siguiente en la parte superior de <code>App\\Providers\\AuthServiceProvider</code></p><div class="language-php"><pre><code><span class="token keyword">use</span> <span class="token package">Illuminate<span class="token punctuation">\\</span>Auth<span class="token punctuation">\\</span>Notifications<span class="token punctuation">\\</span>ResetPassword</span><span class="token punctuation">;</span>
</code></pre></div><p>Agregue lo siguiente en el m\xE9todo <code>boot</code> de <code>AuthServiceProvider</code>, esto crear\xE1 la URL que se usa en el SPA con un token generado:</p><div class="language-php"><pre><code><span class="token class-name static-context">ResetPassword</span><span class="token operator">::</span><span class="token function">createUrlUsing</span><span class="token punctuation">(</span><span class="token keyword">function</span> <span class="token punctuation">(</span><span class="token variable">$user</span><span class="token punctuation">,</span> <span class="token keyword type-hint">string</span> <span class="token variable">$token</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token keyword">return</span> <span class="token function">env</span><span class="token punctuation">(</span><span class="token string single-quoted-string">&#39;SPA_URL&#39;</span><span class="token punctuation">)</span> <span class="token operator">.</span> <span class="token string single-quoted-string">&#39;/reset-password?token=&#39;</span> <span class="token operator">.</span> <span class="token variable">$token</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre></div><p>Para que todo esto funcione, necesitaremos tener una vista de restablecimiento de contrase\xF1a en el SPA que maneje el token y devuelva la nueva contrase\xF1a de los usuarios. Esto se explica, con un enlace al componente, en la p\xE1gina de <a href="./../vue/setup-vue-spa.html">autenticaci\xF3n de Vue</a> bajo el encabezado Reset Password View.</p><h2 id="rutas-api" tabindex="-1">Rutas API <a class="header-anchor" href="#rutas-api" aria-hidden="true">#</a></h2><p>Una vez que tenga toda la autenticaci\xF3n en su lugar, cualquier ruta protegida deber\xE1 usar la protecci\xF3n de middleware <code>auth:sanctum</code>. Esto garantizar\xE1 que el usuario se haya autenticado antes de que pueda ver los datos solicitados de la API. Aqu\xED hay un ejemplo simple de c\xF3mo se ver\xEDan esos puntos finales.</p><div class="language-php"><pre><code><span class="token keyword">use</span> <span class="token package">App<span class="token punctuation">\\</span>Models<span class="token punctuation">\\</span>User</span><span class="token punctuation">;</span>

<span class="token class-name static-context">Route</span><span class="token operator">::</span><span class="token function">middleware</span><span class="token punctuation">(</span><span class="token punctuation">[</span><span class="token string single-quoted-string">&#39;auth:sanctum&#39;</span><span class="token punctuation">]</span><span class="token punctuation">)</span><span class="token operator">-&gt;</span><span class="token function">group</span><span class="token punctuation">(</span><span class="token keyword">function</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token comment">//...</span>
    <span class="token class-name static-context">Route</span><span class="token operator">::</span><span class="token function">get</span><span class="token punctuation">(</span><span class="token string single-quoted-string">&#39;/users/{id}&#39;</span><span class="token punctuation">,</span> <span class="token keyword">function</span> <span class="token punctuation">(</span><span class="token variable">$id</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
      <span class="token keyword">return</span> <span class="token class-name static-context">User</span><span class="token operator">::</span><span class="token function">findOrFail</span><span class="token punctuation">(</span><span class="token variable">$id</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
  <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre></div>`,34),p=[o];function c(i,r,l,u,d,k){return s(),a("div",null,p)}var m=n(t,[["render",c]]);export{f as __pageData,m as default};
